SELECT wr.*, u.username FROM wallet_record wr LEFT JOIN user u ON wr.user_id = u.id
WHERE wr.user_id = #{userId}

    AND wr.type = #{type}

ORDER BY wr.id DESC LIMIT #{offset}, #{limit}

SELECT wr.*, u.username FROM wallet_record wr LEFT JOIN user u ON wr.user_id = u.id


        AND (u.username LIKE CONCAT('%',#{keyword},'%') OR u.phone LIKE CONCAT('%',#{keyword},'%'))


        AND wr.type = #{type}


        AND wr.business_type = #{businessType}


ORDER BY wr.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM wallet_record wr LEFT JOIN user u ON wr.user_id = u.id


        AND (u.username LIKE CONCAT('%',#{keyword},'%') OR u.phone LIKE CONCAT('%',#{keyword},'%'))


        AND wr.type = #{type}


        AND wr.business_type = #{businessType}
